import React, { useEffect, useCallback } from 'react';
import { Linking, Alert } from 'react-native';
import { useNavigation } from '@react-navigation/native';

const DeepLinkHandler = () => {
  const navigation = useNavigation();

  const parseDeepLink = (url) => {
    if (!url) return null;

    const urlParts = url.replace(/.*?:\/\//g, '').split('/');
    const scheme = urlParts[0];
    const route = urlParts[1];
    const params = urlParts.slice(2);

    return {
      scheme,
      route,
      params
    };
  };

  const handleDeepLink = useCallback((url) => {
    if (!url) return;

    const parsed = parseDeepLink(url);
    
    if (!parsed) {
      Alert.alert('Invalid Link', 'The link format is not recognized.');
      return;
    }

    const { route, params } = parsed;

    switch (route) {
      case 'profile':
        if (params[0]) {
          navigation.navigate('Profile', { userId: params[0] });
        } else {
          navigation.navigate('Profile');
        }
        break;

      case 'payment':
        if (params[0] === 'confirm') {
          const transactionId = params[1];
          navigation.navigate('PaymentConfirm', { 
            transactionId: transactionId || null 
          });
        } else {
          navigation.navigate('Payment');
        }
        break;

      case 'product':
        if (params[0]) {
          navigation.navigate('ProductDetail', { productId: params[0] });
        } else {
          navigation.navigate('ProductList');
        }
        break;

      case 'cart':
        navigation.navigate('Cart');
        break;

      case 'orders':
        if (params[0]) {
          navigation.navigate('OrderDetail', { orderId: params[0] });
        } else {
          navigation.navigate('Orders');
        }
        break;

      case 'settings':
        navigation.navigate('Settings');
        break;

      default:
        navigation.navigate('Home');
        break;
    }
  }, [navigation]);

  const getInitialURL = async () => {
    try {
      const initialUrl = await Linking.getInitialURL();
      if (initialUrl) {
        handleDeepLink(initialUrl);
      }
    } catch (error) {
      console.error('Error getting initial URL:', error);
    }
  };

  useEffect(() => {
    getInitialURL();

    const subscription = Linking.addEventListener('url', ({ url }) => {
      handleDeepLink(url);
    });

    return () => {
      subscription.remove();
    };
  }, [handleDeepLink]);

  return null;
};

export default DeepLinkHandler;


