import { Linking, Platform } from 'react-native';

export const openDeepLink = async (url) => {
  const supported = await Linking.canOpenURL(url);
  
  if (supported) {
    await Linking.openURL(url);
  } else {
    console.error(`Don't know how to open this URL: ${url}`);
  }
};

export const parseQueryParams = (url) => {
  const queryString = url.split('?')[1];
  if (!queryString) return {};
  
  const params = {};
  const pairs = queryString.split('&');
  
  pairs.forEach(pair => {
    const [key, value] = pair.split('=');
    params[decodeURIComponent(key)] = decodeURIComponent(value || '');
  });
  
  return params;
};

export const buildDeepLink = (route, params = {}) => {
  let url = `myapp://${route}`;
  
  const paramKeys = Object.keys(params);
  if (paramKeys.length > 0) {
    const queryString = paramKeys
      .map(key => `${encodeURIComponent(key)}=${encodeURIComponent(params[key])}`)
      .join('&');
    url += `?${queryString}`;
  }
  
  return url;
};

export const handlePushNotificationDeepLink = (notification) => {
  const deepLink = notification?.data?.deepLink;
  
  if (deepLink) {
    setTimeout(() => {
      openDeepLink(deepLink);
    }, 1000);
  }
};